   */
  function next(nextFlags = TokenizerFlags.None): Token {
    flags = nextFlags
    advance()
    return createToken()
  }

  /**
   * Advances the tokenizer state.
   */
  function advance() {
    value = ''
    type = 'EOF'

    while (true) {
      if (pos >= end) {
        return (type = 'EOF')
      }

      const ch = source.charAt(pos)
      // Whitespace is irrelevant
      if (isWhiteSpace(ch)) {
        pos++
        continue
      }

      switch (ch) {
        case '(':
          pos++
          parenLeft++
          return (type = ch)
        case ')':
          pos++
          parenRight++
          return (type = ch)
        case '*':
          pos++
          return (type = ch)
        case ',':
          pos++
          return (type = ch)
        case '=':
          pos++
          if ((flags & TokenizerFlags.Dumb) === 0) {
            // Not in dumb-mode, so attempt to skip.
            skipExpression()
          }
          // We need to know that there's a default value so we can
          // skip it if it does not exist when resolving.
          return (type = ch)
        case '/': {
          pos++
          const nextCh = source.charAt(pos)
          if (nextCh === '/') {
            skipUntil((c) => c === '\n', true)
            pos++
          }
          if (nextCh === '*') {
            skipUntil((c) => {
              const closing = source.charAt(pos + 1)
              return c === '*' && closing === '/'
